    "qwerty123", "letmein", "welcome", "welcome123", "admin123",
    "iloveyou", "monkey", "dragon", "football", "baseball",
}

OFFENSIVE_TERMS = {
    # Keep this small in source. In production, load a reviewed moderation denylist.
    "nazi", "terrorist",
}

BIDI_OR_INVISIBLE = {
    "\u200b", "\u200c", "\u200d", "\u2060", "\ufeff",
    "\u202a", "\u202b", "\u202c", "\u202d", "\u202e",
    "\u2066", "\u2067", "\u2068", "\u2069",
}

USERNAME_RE = re.compile(r"^[a-z0-9][a-z0-9._-]{1,30}[a-z0-9]$")
KEYBOARD_RUNS = (
    "abcdefghijklmnopqrstuvwxyz",
    "zyxwvutsrqponmlkjihgfedcba",
    "0123456789",
    "9876543210",
    "qwertyuiop",
    "poiuytrewq",
    "asdfghjkl",
    "lkjhgfdsa",
    "zxcvbnm",
    "mnbvcxz",
)


@dataclass
class CleanRegistration:
    email: str
    email_canonical: str
    email_domain: str
    username: str
    username_canonical: str
    display_name: str
    password: str


class InMemoryRateLimiter:
    def __init__(self) -> None:
        self.hits: dict[str, deque[float]] = defaultdict(deque)
        self.lock = asyncio.Lock()

    async def check(self, key: str, limit: int, window_seconds: int) -> tuple[bool, int]:
        now = time.time()
        async with self.lock:
            q = self.hits[key]
            while q and q[0] <= now - window_seconds:
                q.popleft()

            if len(q) >= limit:
                retry_after = max(1, int(window_seconds - (now - q[0])))
                return False, retry_after

            q.append(now)
            return True, 0


rate_limiter = InMemoryRateLimiter()


@app.middleware("http")
async def security_headers_and_size_limit(request: Request, call_next):
    content_length = request.headers.get("content-length")
    if content_length and content_length.isdigit() and int(content_length) > MAX_BODY_BYTES:
        return error_response(
            413,
            "request_too_large",
            [{"field": "body", "code": "too_large", "message": "Request body is too large."}],
        )

    response = await call_next(request)
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["Referrer-Policy"] = "no-referrer"
    response.headers["Cache-Control"] = "no-store"
    response.headers["Permissions-Policy"] = "geolocation=(), microphone=(), camera=()"
    return response


def error_response(status_code: int, code: str, errors: list[dict[str, str]]) -> JSONResponse:
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "code": code,
            "errors": errors,
        },
    )


def generic_registration_response() -> JSONResponse:
    # Same response for new accounts and already-registered emails.
    return JSONResponse(
        status_code=202,
        content={
            "ok": True,
            "code": "registration_accepted",
            "message": "If registration can be completed, further instructions will be sent.",
        },
    )


def field_error(field: str, code: str, message: str) -> dict[str, str]:
    return {"field": field, "code": code, "message": message}


def hmac_token(value: str) -> str:
    return hmac.new(
        REGISTRATION_PEPPER.encode("utf-8"),
        value.encode("utf-8", errors="ignore"),
        hashlib.sha256,
    ).hexdigest()


def get_client_ip(request: Request) -> str:
    forwarded = request.headers.get("x-forwarded-for")
    if forwarded:
        return forwarded.split(",", 1)[0].strip()
    return request.client.host if request.client else "unknown"


def normalize_text(value: str) -> str:
    return unicodedata.normalize("NFKC", value)


def has_control_or_invisible(value: str) -> bool:
    for ch in value:
        if ch in BIDI_OR_INVISIBLE:
            return True
        category = unicodedata.category(ch)
        if category in {"Cc", "Cf", "Cs"}:
            return True
    return False


def collapse_spaces(value: str) -> str:
    return re.sub(r"\s+", " ", value).strip()


def skeleton(value: str) -> str:
    table = str.maketrans(
        {
            "0": "o",
            "1": "l",
            "3": "e",
            "4": "a",
            "5": "s",
            "7": "t",
            "@": "a",
            "$": "s",
        }
    )
    return value.casefold().translate(table).replace(".", "").replace("_", "").replace("-", "")


def script_name(ch: str) -> str | None:
    if ch.isascii() or ch.isdigit() or ch in " .'-_":
        return None

    name = unicodedata.name(ch, "")
    for script in ("LATIN", "CYRILLIC", "GREEK", "HEBREW", "ARABIC", "DEVANAGARI", "HIRAGANA", "KATAKANA", "HANGUL", "CJK"):
        if script in name:
            return script
    return "OTHER"


def has_mixed_scripts(value: str) -> bool:
    scripts = {script_name(ch) for ch in value}
    scripts.discard(None)
    return len(scripts) > 1


def validate_domain_dns(domain: str) -> bool:
    resolver = dns.resolver.Resolver()
    resolver.lifetime = 2.0
    resolver.timeout = 1.0

    try:
        mx = resolver.resolve(domain, "MX")
        if mx:
            return True
    except Exception:
        pass

    for record_type in ("A", "AAAA"):
        try:
            records = resolver.resolve(domain, record_type)
            if records:
                return True
        except Exception:
            pass

    return False


async def validate_email_field(raw: Any) -> tuple[str | None, str | None, str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, None, None, [field_error("email", "invalid_type", "Email must be a string.")]

    value = normalize_text(raw).strip()

    if not value:
        errors.append(field_error("email", "required", "Email is required."))
        return None, None, None, errors

    if len(value) > 254:
        errors.append(field_error("email", "too_long", "Email must be 254 characters or fewer."))

    if has_control_or_invisible(value):
        errors.append(field_error("email", "invalid_characters", "Email contains invalid characters."))

    if any(ch.isspace() for ch in value):
        errors.append(field_error("email", "whitespace", "Email must not contain whitespace."))

    try:
        validated = validate_email(
            value,
            allow_smtputf8=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
            check_deliverability=False,
        )
    except EmailNotValidError:
        errors.append(field_error("email", "invalid_format", "Email format is invalid."))
        return None, None, None, errors

    ascii_email = validated.ascii_email
    if not ascii_email:
        errors.append(field_error("email", "smtp_utf8_not_supported", "Email must be deliverable without SMTPUTF8-only local parts."))
        return None, None, None, errors

    local, domain = ascii_email.rsplit("@", 1)
    local_canonical = local.casefold()
    domain_ascii = domain.casefold()

    if len(local.encode("utf-8")) > 64:
        errors.append(field_error("email", "local_part_too_long", "Email local part is too long."))

    if ".." in local or local.startswith(".") or local.endswith("."):
        errors.append(field_error("email", "invalid_local_part", "Email local part is invalid."))

    try:
        domain_ascii = idna.encode(domain_ascii, uts46=True).decode("ascii").casefold()
        unicode_domain = idna.decode(domain_ascii)
    except idna.IDNAError:
        errors.append(field_error("email", "invalid_domain", "Email domain is invalid."))
        return None, None, None, errors

    if has_mixed_scripts(unicode_domain):
        errors.append(field_error("email", "suspicious_idn", "Email domain uses suspicious mixed scripts."))

    labels = domain_ascii.split(".")
    tld = labels[-1] if labels else ""

    if len(domain_ascii) > 253 or len(labels) < 2:
        errors.append(field_error("email", "invalid_domain", "Email domain must be a public domain."))

    if tld.isdigit() or len(tld) < 2:
        errors.append(field_error("email", "invalid_tld", "Email top-level domain is invalid."))

    for label in labels:
        if not label or len(label) > 63 or label.startswith("-") or label.endswith("-") or "_" in label:
            errors.append(field_error("email", "invalid_domain_label", "Email domain contains an invalid label."))
            break

    blocked_suffixes = {"localhost", "local", "internal", "invalid", "example", "test"}
    if tld in blocked_suffixes or domain_ascii in blocked_suffixes:
        errors.append(field_error("email", "non_public_domain", "Email domain must be public."))

    try:
        ipaddress.ip_address(domain_ascii)
        errors.append(field_error("email", "ip_domain_not_allowed", "Email domain must not be an IP address."))
    except ValueError:
        pass

    if domain_ascii in DISPOSABLE_DOMAINS or any(domain_ascii.endswith("." + d) for d in DISPOSABLE_DOMAINS):
        errors.append(field_error("email", "disposable_email", "Disposable email addresses are not accepted."))

    if local_canonical in ROLE_EMAIL_LOCALPARTS:
        errors.append(field_error("email", "role_email_not_allowed", "Role-based email addresses are not accepted."))

    dns_ok = await asyncio.to_thread(validate_domain_dns, domain_ascii)
    if not dns_ok:
        errors.append(field_error("email", "domain_not_deliverable", "Email domain does not appear to accept mail."))

    canonical = f"{local_canonical}@{domain_ascii}"
    normalized = f"{local}@{domain_ascii}"

    return normalized, canonical, domain_ascii, errors


def validate_username_field(raw: Any) -> tuple[str | None, str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, None, [field_error("username", "invalid_type", "Username must be a string.")]

    original = raw
    value = normalize_text(raw).strip().casefold()

    if not value:
        errors.append(field_error("username", "required", "Username is required."))
        return None, None, errors

    if original != original.strip():
        errors.append(field_error("username", "surrounding_whitespace", "Username must not start or end with whitespace."))

    if any(ord(ch) > 127 for ch in original):
        errors.append(field_error("username", "non_ascii", "Username must use ASCII characters only."))

    if len(value) < 3:
        errors.append(field_error("username", "too_short", "Username must be at least 3 characters."))

    if len(value) > 32:
        errors.append(field_error("username", "too_long", "Username must be 32 characters or fewer."))

    if len(value.encode("utf-8")) > 64:
        errors.append(field_error("username", "too_large", "Username is too large."))

    if not USERNAME_RE.fullmatch(value):
        errors.append(field_error("username", "invalid_characters", "Username may contain only letters, numbers, dots, underscores, and hyphens, and must start and end with a letter or number."))

    if re.search(r"[._-]{2,}", value):
        errors.append(field_error("username", "repeated_separators", "Username must not contain repeated separators."))

    if ".." in value or "/" in value or "\\" in value:
        errors.append(field_error("username", "path_like", "Username must not resemble a path."))

    try:
        ipaddress.ip_address(value)
        errors.append(field_error("username", "ip_address", "Username must not be an IP address."))
    except ValueError:
        pass

    compact = skeleton(value)

    if value in RESERVED_USERNAMES or compact in RESERVED_USERNAMES:
        errors.append(field_error("username", "reserved", "Username is unavailable."))

    if any(term in compact for term in OFFENSIVE_TERMS):
        errors.append(field_error("username", "blocked_content", "Username is unavailable."))

    return value, value, errors


def validate_display_name_field(raw: Any) -> tuple[str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, [field_error("display_name", "invalid_type", "Display name must be a string.")]

    value = collapse_spaces(normalize_text(raw))
    sanitized = bleach.clean(value, tags=[], attributes={}, protocols=[], strip=True)
    sanitized = collapse_spaces(sanitized)

    if not sanitized:
        errors.append(field_error("display_name", "required", "Display name is required."))

    if len(sanitized) > 80:
        errors.append(field_error("display_name", "too_long", "Display name must be 80 characters or fewer."))

    if len(sanitized.encode("utf-8")) > 160:
        errors.append(field_error("display_name", "too_large", "Display name is too large."))

    if has_control_or_invisible(value):
        errors.append(field_error("display_name", "invalid_characters", "Display name contains invalid characters."))

    if sanitized != value:
        errors.append(field_error("display_name", "html_not_allowed", "Display name must not contain HTML."))

    if has_mixed_scripts(sanitized):
        errors.append(field_error("display_name", "suspicious_unicode", "Display name uses suspicious mixed scripts."))

    compact = skeleton(sanitized)
    if compact in RESERVED_USERNAMES or any(term in compact for term in OFFENSIVE_TERMS):
        errors.append(field_error("display_name", "blocked_content", "Display name is unavailable."))

    return sanitized, errors


def password_similarity_error(password: str, candidates: list[str]) -> bool:
    pwd = skeleton(password)
    if len(pwd) < 8:
        return True

    for candidate in candidates:
        candidate = skeleton(candidate)
        if len(candidate) < 3:
            continue

        if candidate in pwd or pwd in candidate:
            return True

        if len(candidate) >= 5 and SequenceMatcher(None, pwd, candidate).ratio() >= 0.72:
            return True

    return False


def has_sequential_run(password: str) -> bool:
    lowered = password.casefold()
    for run in KEYBOARD_RUNS:
        for i in range(0, len(run) - 3):
            if run[i : i + 4] in lowered:
                return True
    return False


async def breached_password_count(password: str) -> int | None:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        async with httpx.AsyncClient(timeout=3.0) as client:
            response = await client.get(
                f"https://api.pwnedpasswords.com/range/{prefix}",
                headers={"Add-Padding": "true", "User-Agent": "secure-registration-example"},
            )
            response.raise_for_status()
    except Exception:
        return None

    for line in response.text.splitlines():
        candidate_suffix, _, count = line.partition(":")
        if secrets.compare_digest(candidate_suffix.upper(), suffix):
            return int(count or "0")

    return 0


async def validate_password_field(
    raw: Any,
    email: str | None,
    username: str | None,
    display_name: str | None,
) -> tuple[str | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    if not isinstance(raw, str):
        return None, [field_error("password", "invalid_type", "Password must be a string.")]

    password = normalize_text(raw)

    if not password:
        errors.append(field_error("password", "required", "Password is required."))
        return None, errors

    if password != raw:
        errors.append(field_error("password", "unicode_normalized", "Password contains characters that normalize ambiguously."))

    if len(password) < 12:
        errors.append(field_error("password", "too_short", "Password must be at least 12 characters."))

    if len(password) > MAX_PASSWORD_CHARS:
        errors.append(field_error("password", "too_long", "Password must be 128 characters or fewer."))

    if len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        errors.append(field_error("password", "too_large", "Password is too large."))

    if password != password.strip():
        errors.append(field_error("password", "surrounding_whitespace", "Password must not start or end with whitespace."))

    if has_control_or_invisible(password) or any(ch in password for ch in "\r\n\t\x00"):
        errors.append(field_error("password", "invalid_characters", "Password contains invalid control characters."))

    categories = {
        "lower": any(ch.islower() for ch in password),
        "upper": any(ch.isupper() for ch in password),
        "digit": any(ch.isdigit() for ch in password),
        "symbol": any(not ch.isalnum() and not ch.isspace() for ch in password),
    }

    if not all(categories.values()):
        errors.append(field_error("password", "complexity", "Password must include uppercase, lowercase, number, and symbol characters."))

    lowered = password.casefold()
    compact = skeleton(password)

    if lowered in COMMON_PASSWORDS or compact in COMMON_PASSWORDS:
        errors.append(field_error("password", "common_password", "Password is too common."))

    if re.search(r"(.)\1{3,}", lowered):
        errors.append(field_error("password", "repeated_characters", "Password contains too many repeated characters."))

    if has_sequential_run(lowered):
        errors.append(field_error("password", "sequential_characters", "Password contains predictable character sequences."))

    candidates = []
    if email:
        local, _, domain = email.partition("@")
        candidates.extend([email, local, domain.split(".")[0]])
    if username:
        candidates.append(username)
    if display_name:
        candidates.extend(display_name.split())

    if password_similarity_error(password, candidates):
        errors.append(field_error("password", "too_similar", "Password must not be similar to your email, username, or display name."))

    breach_count = await breached_password_count(password)
    if breach_count and breach_count > 0:
        errors.append(field_error("password", "breached", "Password has appeared in a known data breach."))

    return password, errors


def origin_allowed(origin: str) -> bool:
    parsed = urlparse(origin)
    if parsed.scheme not in {"https", "http"}:
        return False

    normalized = f"{parsed.scheme}://{parsed.netloc}"
    return any(secrets.compare_digest(normalized, allowed) for allowed in ALLOWED_ORIGINS)


async def csrf_protect(request: Request) -> JSONResponse | None:
    origin = request.headers.get("origin")
    referer = request.headers.get("referer")
    has_cookie = bool(request.headers.get("cookie"))

    if origin and not origin_allowed(origin):
        return error_response(
            403,
            "csrf_failed",
            [field_error("request", "invalid_origin", "Request origin is not allowed.")],
        )

    if has_cookie and not origin:
        if not referer or not origin_allowed(referer):
            return error_response(
                403,
                "csrf_failed",
                [field_error("request", "missing_origin", "Browser requests with cookies require a trusted Origin or Referer.")],
            )

    csrf_cookie = request.cookies.get("csrf_token")
    csrf_header = request.headers.get("x-csrf-token")

    if csrf_cookie or csrf_header:
        if not csrf_cookie or not csrf_header or not secrets.compare_digest(csrf_cookie, csrf_header):
            return error_response(
                403,
                "csrf_failed",
                [field_error("request", "invalid_csrf_token", "CSRF token is invalid.")],
            )

    return None


async def read_json_body(request: Request) -> tuple[dict[str, Any] | None, JSONResponse | None]:
    content_type = request.headers.get("content-type", "").split(";", 1)[0].strip().lower()
    if content_type != "application/json":
        return None, error_response(
            415,
            "unsupported_media_type",
            [field_error("body", "content_type", "Content-Type must be application/json.")],
        )

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return None, error_response(
            413,
            "request_too_large",
            [field_error("body", "too_large", "Request body is too large.")],
        )

    try:
        data = json.loads(body)
    except json.JSONDecodeError:
        return None, error_response(
            400,
            "invalid_json",
            [field_error("body", "invalid_json", "Request body must be valid JSON.")],
        )

    if not isinstance(data, dict):
        return None, error_response(
            400,
            "invalid_body",
            [field_error("body", "invalid_type", "Request body must be a JSON object.")],
        )

    return data, None


async def validate_registration_payload(data: dict[str, Any]) -> tuple[CleanRegistration | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    required = {"email", "username", "password", "display_name"}
    allowed = required

    for key in sorted(required - data.keys()):
        errors.append(field_error(key, "missing", f"{key} is required."))

    for key in sorted(data.keys() - allowed):
        errors.append(field_error(key, "unknown_field", "Unknown field is not allowed."))

    email, email_canonical, email_domain, email_errors = await validate_email_field(data.get("email"))
    username, username_canonical, username_errors = validate_username_field(data.get("username"))
    display_name, display_errors = validate_display_name_field(data.get("display_name"))
    password, password_errors = await validate_password_field(
        data.get("password"),
        email_canonical or data.get("email") if isinstance(data.get("email"), str) else None,
        username_canonical or data.get("username") if isinstance(data.get("username"), str) else None,
        display_name or data.get("display_name") if isinstance(data.get("display_name"), str) else None,
    )

    errors.extend(email_errors)
    errors.extend(username_errors)
    errors.extend(display_errors)
    errors.extend(password_errors)

    if errors:
        return None, errors

    return CleanRegistration(
        email=email,
        email_canonical=email_canonical,
        email_domain=email_domain,
        username=username,
        username_canonical=username_canonical,
        display_name=display_name,
        password=password,
    ), []


def username_exists(username_canonical: str) -> bool:
    row = db.execute(
        "SELECT 1 FROM users WHERE username_canonical = ? LIMIT 1",
        (username_canonical,),
    ).fetchone()
    return row is not None


def insert_user(clean: CleanRegistration, request: Request, password_hash: str) -> str:
    ip_hash = hmac_token(get_client_ip(request))
    ua_hash = hmac_token(request.headers.get("user-agent", ""))
    now = int(time.time())

    try:
        db.execute(
            """
            INSERT INTO users (
                email,
                email_canonical,
                email_domain,
                username,
                username_canonical,
                display_name,
                password_hash,
                registration_ip_hash,
                user_agent_hash,
                created_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                clean.email,
                clean.email_canonical,
                clean.email_domain,
                clean.username,
                clean.username_canonical,
                clean.display_name,
                password_hash,
                ip_hash,
                ua_hash,
                now,
            ),
        )
        return "created"
    except sqlite3.IntegrityError as exc:
        message = str(exc).casefold()
        if "username_canonical" in message:
            return "username_conflict"
        if "email_canonical" in message:
            return "email_conflict"
        return "conflict"


@app.post("/api/register")
async def register(request: Request):
    csrf_error = await csrf_protect(request)
    if csrf_error:
        return csrf_error

    client_ip = get_client_ip(request)
    ok, retry_after = await rate_limiter.check(f"ip:{hmac_token(client_ip)}", limit=10, window_seconds=3600)
    if not ok:
        response = error_response(
            429,
            "rate_limited",
            [field_error("request", "rate_limited", "Too many registration attempts. Try again later.")],
        )
        response.headers["Retry-After"] = str(retry_after)
        return response

    data, body_error = await read_json_body(request)
    if body_error:
        return body_error

    raw_email = data.get("email")
    if isinstance(raw_email, str):
        email_key = hmac_token(normalize_text(raw_email).strip().casefold())
        ok, retry_after = await rate_limiter.check(f"email:{email_key}", limit=5, window_seconds=3600)
        if not ok:
            response = error_response(
                429,
                "rate_limited",
                [field_error("request", "rate_limited", "Too many registration attempts. Try again later.")],
            )
            response.headers["Retry-After"] = str(retry_after)
            return response

    clean, validation_errors = await validate_registration_payload(data)
    if validation_errors:
        return error_response(422, "validation_failed", validation_errors)

    # Hash before uniqueness handling so existing-email paths do not skip expensive work.
    password_hash = ph.hash(clean.password)

    if username_exists(clean.username_canonical):
        return error_response(
            409,
            "username_unavailable",
            [field_error("username", "unavailable", "Username is unavailable.")],
        )

    result = insert_user(clean, request, password_hash)

    if result == "username_conflict":
        return error_response(
            409,
            "username_unavailable",
            [field_error("username", "unavailable", "Username is unavailable.")],
        )

    if result in {"email_conflict", "created"}:
        return generic_registration_response()

    return error_response(
        409,
        "registration_conflict",
        [field_error("request", "conflict", "Registration could not be completed.")],
    )
